'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useCart } from '../context/CartContext';
import { useFavourites } from '../context/FavouritesContext';
import { ShoppingCart, Check } from 'lucide-react';

export default function ProductCard({
  id,
  image,
  title,
  currentPrice,
  originalPrice,
  isFavorite = false
}) {
  const [isAddingToCart, setIsAddingToCart] = useState(false);
  const [addedToCart, setAddedToCart] = useState(false);
  const { addToCart } = useCart();
  const { toggleFavourite, isFavourite } = useFavourites();

  const favourite = isFavourite(id);

  const handleAddToCart = async (e) => {
    e.preventDefault();
    e.stopPropagation();

    setIsAddingToCart(true);

    // Create product object for cart
    const product = {
      id: id || 1,
      title,
      image,
      currentPrice: typeof currentPrice === 'string' ? parseFloat(currentPrice.replace('$', '')) : currentPrice,
      originalPrice: originalPrice ? (typeof originalPrice === 'string' ? parseFloat(originalPrice.replace('$', '')) : originalPrice) : null
    };

    addToCart(product);

    setTimeout(() => {
      setIsAddingToCart(false);
      setAddedToCart(true);
      setTimeout(() => setAddedToCart(false), 2000);
    }, 500);
  };

  return (
    <div className="product-card-link">
      <div className="product-card">
        <div className="product-image-wrapper">
          <img
            src={image}
            alt={title}
            className="product-image"
          />
          <div
            className={`product-favorite ${favourite ? 'active' : ''}`}
            onClick={(e) => {
              e.preventDefault();
              e.stopPropagation();
              toggleFavourite({
                id,
                title,
                image,
                currentPrice: typeof currentPrice === 'string' ? parseFloat(currentPrice.replace('$', '')) : currentPrice,
                originalPrice: originalPrice ? (typeof originalPrice === 'string' ? parseFloat(originalPrice.replace('$', '')) : originalPrice) : null
              });
            }}
          >
            <svg width="18" height="18" viewBox="0 0 24 24" fill={favorite ? "#FF0000" : "none"} stroke={favorite ? "#FF0000" : "#666666"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>
            </svg>
          </div>
        </div>
        <div className="product-info">
          <Link href={`/products/${id || 1}`} className="product-title-link">
            <div className="product-title">{title}</div>
          </Link>
          <div className="product-price">
            <span className="product-price-current">${typeof currentPrice === 'string' ? currentPrice : currentPrice.toFixed(2)}</span>
            {originalPrice && (
              <span className="product-price-original">${typeof originalPrice === 'string' ? originalPrice : originalPrice.toFixed(2)}</span>
            )}
          </div>
          <button
            className={`add-to-cart-btn ${addedToCart ? 'added' : ''}`}
            onClick={handleAddToCart}
            disabled={isAddingToCart}
          >
            {isAddingToCart ? (
              <div className="loading-spinner"></div>
            ) : addedToCart ? (
              <>
                <Check size={16} />
                Added
              </>
            ) : (
              <>
                <ShoppingCart size={16} />
                Add to Cart
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

