'use client';

import Header from './components/Header';
import SearchBar from './components/SearchBar';
import SectionHeader from './components/SectionHeader';
import CategoryCard from './components/CategoryCard';
import ProductCard from './components/ProductCard';
import PromoBanner from './components/PromoBanner';
import BottomNav from './components/BottomNav';
import { categories, featuredProducts, newArrivals, hotProducts, topRated, bestSelling, luxuryProducts, ecoProducts, travelEssentials, securityProducts } from './data/products';

export default function Home() {
  return (
    <div className="page-content">
      <div className="container">
        <Header />
        <SearchBar cartCount={3} />
        
        <div className="categories-container">
          <SectionHeader title="Categories" />
          <div className="categories-scroll">
            {categories.map((category) => (
              <CategoryCard
                key={category.id}
                image={category.image}
                label={category.name}
              />
            ))}
          </div>
        </div>

        <PromoBanner currentSlide={2} />

        <div className="products-container">
          <SectionHeader title="Featured" />
          <div className="products-scroll">
            {featuredProducts.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="New Arrivals" />
          <div className="products-scroll">
            {newArrivals.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Hot" />
          <div className="products-scroll">
            {hotProducts.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Top Rated" />
          <div className="products-scroll">
            {topRated.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Best Selling" />
          <div className="products-scroll">
            {bestSelling.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Luxury" />
          <div className="products-scroll">
            {luxuryProducts.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Eco" />
          <div className="products-scroll">
            {ecoProducts.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Travel Essentials" />
          <div className="products-scroll">
            {travelEssentials.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>

        <div className="products-container">
          <SectionHeader title="Security" />
          <div className="products-scroll">
            {securityProducts.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                image={product.image}
                title={product.title}
                currentPrice={product.currentPrice}
                originalPrice={product.originalPrice}
                isFavorite={product.isFavorite}
              />
            ))}
          </div>
        </div>
      </div>
      <BottomNav />
    </div>
  );
}
